mapper.select:
SELECT * FROM oauth_refresh_token
WHERE user_id = #{userId}
  AND client_id = #{clientId}
  AND revoked = 0
  AND expires_at > NOW()
ORDER BY create_time DESC

mapper.update:
UPDATE oauth_refresh_token
SET revoked = 1
WHERE id IN (
    SELECT id FROM (
        SELECT id FROM oauth_refresh_token
        WHERE user_id = #{userId}
          AND client_id = #{clientId}
          AND revoked = 0
          AND expires_at > NOW()
        ORDER BY create_time ASC
        LIMIT 1000 OFFSET #{keepCount}
    ) t
)
